import React, { Component } from 'react'
import LearnAdjective from './LearnAdjective'
import LearnAnimal from './LearnAnimal'
import LearnNoun from './LearnNoun'
import LearnVerb from './LearnVerb'

class LearnWord extends Component {

    render() {

        return (
            <div className="container">
                <div className="row mt-5">
                    <LearnVerb />
                    <LearnAdjective />
                    <LearnNoun />
                    <LearnAnimal />
                </div>
            </div>
        )
    }
}

export default LearnWord;