import React, { Component } from 'react'
import ChooseTheCorrectAnswerForOneWord from "../../components/models/ChooseTheCorrectAnswerForOneWord";
import ArticoloIndeterminativoContext from '../../contexts/ArticoloIndeterminativoContext';

class ArticoliIndeterminativo extends Component {

  static contextType = ArticoloIndeterminativoContext;

  state = {
    articoloIndeterminativoExercises : this.context,
  }

  render() {
    return (
      <>
        <table className="table table-bordered">
        <thead>
            <tr>
              <th className="align-middle" rowspan="2">Parole che cominciano con</th>
              <th className="text-center h5 text-danger" colspan="2">MASCHILE</th>
              <th className="text-center h5 text-danger" colspan="2">FEMMINILE</th>
            </tr>
            <tr>
                <th className="text-center h6 text-danger">SINGOLARE</th>
                <th className="text-center h6 text-danger">PLURALE</th>
                <th className="text-center h6 text-danger">SINGOLARE</th>
                <th className="text-center h6 text-danger">PLURALE</th>
            </tr>
        </thead>
        <tbody>
            <tr>
              <th className="h5 text-danger">CONSONANTE</th>
              <td className="h5">un</td>
              <td className="h5">dei</td>
              <td className="h5">una</td>
              <td className="h5">delle</td>
            </tr>
            <tr>
              <th className="h5 text-danger">VOCALE</th>
              <td className="h5">un</td>
              <td className="h5">degli</td>
              <td className="h5">un'</td>
              <td className="h5">delle</td>
            </tr>
            <tr>
              <th className="h5 text-danger">Z, X, GN, Y, PN, PS <br /> S + CONSONANTE</th>
              <td className="h5">uno</td>
              <td className="h5">degli</td>
            </tr>
        </tbody>
    </table>

      <ChooseTheCorrectAnswerForOneWord db={this.state.articoloIndeterminativoExercises} />
    </>
    )
  }
}

export default ArticoliIndeterminativo;