import React, { Component } from 'react'
import VerbContext from '../../contexts/VerbContext';

class LearnVerb extends Component {

    static contextType = VerbContext;

    state = {
        verbs : this.context,
        currentVerb : ""
    }

    componentDidMount(){
        this.getNewVerb()
    }

    getNewVerb = () => {
        const randomNumber = Math.floor(Math.random() * this.state.verbs.length);
        this.setState({
            currentVerb : this.state.verbs[randomNumber]
        })
    };

    render() {
        return (
        <div className="col-md-4 text-center mb-5">
            <div className="card shadow-3-strong">
                <div className="card-body">
                  <h2 className="card-title my-4">{this.state.currentVerb.italian}</h2>
                  <hr />
                  <h2 className="card-title my-4">{this.state.currentVerb.english}</h2>
                  <hr />
                  <h2 className="card-title my-4">{this.state.currentVerb.turkish}</h2>
                  <button onClick={this.getNewVerb} className="btn btn-info mt-3">New Verb</button>                      
                </div>
            </div>
        </div>
        ) 
    }
}

export default LearnVerb;