import React, { Component } from 'react'

class MiPresento extends Component {
    render() {
        return (
        <div class="accordion-item">
            <h2 class="accordion-header">
                <button class="accordion-button collapsed" type="button" data-mdb-toggle="collapse"
                    data-mdb-target="#mi-presento" aria-expanded="false" >
                    Mi presento
                </button>
            </h2>
            <div id="mi-presento" class="accordion-collapse collapse">
                <div class="accordion-body">
                    <p><span className="paragraph-numbers">1</span>Ciao a tutti! Mi chiamo Laura Cecchetti e ho 28 anni. Abito a Locarno, in Ticino, in una bella
                    casetta con giardino. Sono sposata e ho un figlio. Si chiama Matteo e ha tre anni. Va all’asilo nido e
                    ha tanti amici. Mio marito si chiama Davide e fa l’ingegnere. Abbiamo anche un cane che si chiama
                    Leo. È molto simpatico e affettuoso. Sono insegnante e lavoro in una scuola elementare. I miei alunni sono molto bravi. Il mio lavoro mi piace molto. Nel tempo libero mi piace fare passeggiate con la mia famiglia. La sera leggo un libro o guardo un bel film alla TV.</p>
                    <p><span className="paragraph-numbers">2</span>Ciao a tutti! Mi chiamo Pietro Sartori. Ho 18 anni e vivo a Lugano in un appartamento in centro. I
                    miei genitori si chiamano Marta e Giulio. Mia madre è casalinga, mio padre è poliziotto e lavora per
                    il Comune. Ho una sorella, Chiara, e un fratello, Luca. Al momento lavoro in un supermercato, ma l’anno prossimo vorrei cominciare l’università. Vorrei studiare matematica: è difficile, ma molto interessante.
                    Nel tempo libero faccio sport, incontro gli amici o ascolto la mia musica preferita. Non mi piace leggere.</p>
                    <p><span className="paragraph-numbers">3</span>Ciao a tutti! Sono Michele Morelli e ho 54 anni. Sono medico e lavoro in un ospedale. Il mio lavoro
                    è molto pesante, ma mi piace tantissimo. È bello curare i malati e aiutare le persone che hanno
                    bisogno. Sono sposato con Federica che fa la segretaria in uno studio di avvocati. Abbiamo quattro figli: il
                    maggiore è sposato e lavora in banca, le due figlie gemelle studiano architettura. Il figlio minore va
                    ancora al liceo. Da grande vuole fare il giudice. Ho poco tempo libero, ma nelle vacanze mi piace viaggiare con la mia famiglia o andare in montagna.</p>
                </div>
            </div>
        </div>
        )
    }
}

export default MiPresento;