import React, { Component } from 'react'
import AnimalContext from '../../contexts/AnimalContext';

class LearnAnimal extends Component {

    static contextType = AnimalContext;

    state = {
        animals : this.context,
        currentAnimal : ""
    }

    componentDidMount(){
        this.getNewAnimal()
    }

    getNewAnimal = () => {
        const randomNumber = Math.floor(Math.random() * this.state.animals.length);
        this.setState({
            currentAnimal : this.state.animals[randomNumber]
        })
    };

    render() {
        return (
        <div className="col-md-4 text-center mb-5">
            <div className="card shadow-3-strong">
                <div className="card-body">
                  <h2 className="card-title my-4">{this.state.currentAnimal.italian}</h2>
                  <hr />
                  <h2 className="card-title my-4">{this.state.currentAnimal.english}</h2>
                  <hr />
                  <h2 className="card-title my-4">{this.state.currentAnimal.turkish}</h2>
                  <button onClick={this.getNewAnimal} className="btn btn-info mt-3">New Animal</button>                      
                </div>
            </div>
        </div>
        )          
    }
}

export default LearnAnimal;