import React, { Component } from 'react'
import AdjectiveContext from '../../contexts/AdjectiveContext';

class LearnAdjective extends Component {

    static contextType = AdjectiveContext;

    state = {
        adjectives : this.context,
        currentAdjective : ""
    }

    componentDidMount(){
        this.getNewAdjective()
    }

    getNewAdjective = () => {
        const randomNumber = Math.floor(Math.random() * this.state.adjectives.length);
        this.setState({
            currentAdjective : this.state.adjectives[randomNumber]
        })
    };

    render() {
        return (
        <div className="col-md-4 text-center mb-5">
            <div className="card shadow-3-strong">
                <div className="card-body">
                  <h2 className="card-title my-4">{this.state.currentAdjective.italian}</h2>
                  <hr />
                  <h2 className="card-title my-4">{this.state.currentAdjective.english}</h2>
                  <hr />
                  <h2 className="card-title my-4">{this.state.currentAdjective.turkish}</h2>
                  <button onClick={this.getNewAdjective} className="btn btn-info mt-3">New Adjective</button>                      
                </div>
            </div>
        </div>
        )          
    }
}

export default LearnAdjective;