import React, { Component } from 'react'
import ArticoliDeterminativo from './ArticoliDeterminativo'
import ArticoliIndeterminativo from './ArticoliIndeterminativo'
import Presente from './Presente'
import PassatoProssimo from './PassatoProssimo'
import FuturoSemplice from './FuturoSemplice'

class Grammar extends Component {
    render() {
        return (
            <div className="container">
                <div className="row mt-5">
                    <div className="col-md-3">
                        <div className="list-group" id="list-tab">
                            {/* articolo determinativo */}
                            <a className="list-group-item list-group-item-action active" data-mdb-toggle="list" href="#articolo-determinativo">Articolo Determinativo</a>
                            {/* articolo indeterminativo */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#articolo-indeterminativo">Articolo Indeterminativo</a>
                            {/* presente */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#presente">Presente</a>
                            {/* passato prossimo */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#passato-prossimo">Passato Prossimo</a>
                            {/* futuro semplice */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#futuro-semplice">Futuro Semplice</a>
                        </div>
                    </div>

                    <div className="col-md-9">
                        <div className="tab-content">
                             {/* articolo determinativo */}
                            <div className="tab-pane fade show active" id="articolo-determinativo">
                                <ArticoliDeterminativo />
                            </div>
                            {/* articolo indeterminativo */}
                            <div className="tab-pane fade" id="articolo-indeterminativo">
                                <ArticoliIndeterminativo />
                            </div>
                            {/* presente */}
                            <div className="tab-pane fade" id="presente">
                                <Presente />
                            </div>
                            {/* passato prossimo */}
                            <div className="tab-pane fade" id="passato-prossimo">
                                <PassatoProssimo />
                            </div>
                            {/* futuro semplice */}
                            <div className="tab-pane fade" id="futuro-semplice">
                                <FuturoSemplice />
                            </div>
                        </div>
                    </div>

                </div>
            </div>
        )
    }
}

export default Grammar;