import React, { Component } from 'react'
import NounContext from '../../contexts/NounContext';

class LearnNoun extends Component {

    static contextType = NounContext;

    state = {
        nouns : this.context,
        currentNoun : ""
    }

    componentDidMount(){
        this.getNewNoun()
    }

    getNewNoun = () => {
        const randomNumber = Math.floor(Math.random() * this.state.nouns.length);
        this.setState({
            currentNoun : this.state.nouns[randomNumber]
        })
    };

    render() {
        return (     
        <div className="col-md-4 text-center mb-5">
            <div className="card shadow-3-strong">
                <div className="card-body">
                  <h2 className="card-title my-4">{this.state.currentNoun.italian}</h2>
                  <hr />
                  <h2 className="card-title my-4">{this.state.currentNoun.english}</h2>
                  <hr />
                  <h2 className="card-title my-4">{this.state.currentNoun.turkish}</h2>
                  <button onClick={this.getNewNoun} className="btn btn-info mt-3">New Noun</button>                      
                </div>
            </div>
        </div>
        )          
    }
}

export default LearnNoun;