import React, { Component } from 'react'
import { v4 as uuidv4 } from 'uuid';

class ChooseTheCorrectAnswerForOneWord extends Component {

  state = {
    wordList : this.props.db.wordList,
    answerList : this.props.db.answerList,
    optionList : this.props.db.optionList,
    key : this.props.db.key,
    isShowAnswers : false
  }

  showAnswers = () => {
    this.setState({
      isShowAnswers : !this.state.isShowAnswers
    })
  }

  checkAnswer = (e) => {
    const id = e.target.id;
    if(e.target.value === this.state.answerList[id]){
      document.getElementById(`${this.state.key}${id}`).innerHTML = '<i class="fas fa-check-circle true-option"></i>'
    }else{
      document.getElementById(`${this.state.key}${id}`).innerHTML = '<i class="fas fa-times-circle false-option"></i>'
    }
  }

  render() {
    return (
    <>
      <h2 className="mt-5">Exercises</h2>
      <hr />
      <div className="row">

        {this.state.wordList.map((word, index) => (
          <div className="col-md-4 mb-4">
            <span>{index+1}.</span>

            <select id={index} onChange={this.checkAnswer} class="form-select form-select-sm inline-select">
              <option>choose</option>
              {this.state.optionList.map(option => (
                <option>{option}</option>
              ))}
            </select>

            <span>{word}</span>

            <span id={this.state.key + index}></span>
          </div>
        ))}

      </div>

      <div className="row mb-5">
        <div className="col-md-12">        
          <button onClick={this.showAnswers} className="btn btn-primary float-end ms-3">
            {
              this.state.isShowAnswers ? "Hide Answers" : "Show Answers"
            }
          </button>          
        </div>
      </div>

      {
        this.state.isShowAnswers
          ? <div className="row mb-5"> 
              <h2 className="mt-5">Answers</h2>
              <hr />
              {this.state.wordList.map((word, index) => (
                <div className="col-md-3">
                  <span>{index+1}. </span>
                  <span className="text-danger"><strong>{this.state.answerList[index]}</strong> </span>
                  <span>{word}</span>
                </div>
              ))}
            </div>
          : null
      }
    </>
    )
  }
}

export default ChooseTheCorrectAnswerForOneWord;